"use client";

import { useParams } from "next/navigation";
import { useEffect, useState } from "react";
import { db } from "../../../lib/firebase";
import { collection, getDocs, query, where, addDoc, doc, setDoc } from "firebase/firestore";

export default function ScanPage() {
  const params = useParams();
  const qr_id = params.qr_id;

  const [vehicle, setVehicle] = useState(null);
  const [loading, setLoading] = useState(true);
  const [formData, setFormData] = useState({
    plate_number: "",
    make: "",
    model: "",
    owner_email: "",
    ice_name: "",
    ice_phone: "",
    ice_relationship: ""
  });
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    if (!qr_id) return;

    async function fetchVehicle() {
      const vehiclesRef = collection(db, "vehicles");
      const q = query(vehiclesRef, where("qr_id", "==", qr_id));
      const querySnapshot = await getDocs(q);

      if (!querySnapshot.empty) {
        const docData = querySnapshot.docs[0].data();
        const vehicleId = querySnapshot.docs[0].id;

        // Fetch ICE contacts
        const iceRef = collection(db, `vehicles/${vehicleId}/ice_contacts`);
        const iceSnapshot = await getDocs(iceRef);
        const iceContacts = iceSnapshot.docs.map(doc => doc.data());

        setVehicle({ id: vehicleId, ...docData, ice_contacts: iceContacts });
      }
      setLoading(false);
    }

    fetchVehicle();
  }, [qr_id, submitted]);

  const handleChange = (e) => {
    setFormData({...formData, [e.target.name]: e.target.value});
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Create vehicle document
    const vehicleRef = doc(collection(db, "vehicles"));
    await setDoc(vehicleRef, {
      qr_id: qr_id,
      plate_number: formData.plate_number,
      make: formData.make,
      model: formData.model,
      owner_email: formData.owner_email // new email field
    });

    // Create ICE contact subcollection
    const iceRef = collection(db, `vehicles/${vehicleRef.id}/ice_contacts`);
    await addDoc(iceRef, {
      name: formData.ice_name,
      phone: formData.ice_phone,
      relationship: formData.ice_relationship
    });

    setSubmitted(true); // trigger refetch
  };

  // Function to send pre-written emails
  const sendPresetEmail = (message) => {
    if (!vehicle?.owner_email) {
      alert("Owner email not found.");
      return;
    }
    const subject = "DriveAlert QR Notification";
    const body = `Hello,

${message}

Vehicle: ${vehicle.plate_number} (${vehicle.make} ${vehicle.model})

Regards,
DriveAlert User`;

    window.location.href = `mailto:${vehicle.owner_email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  };

  if (loading) return <p>Loading...</p>;

  // If vehicle exists → show contacts and email options
  if (vehicle) {
    return (
      <div style={{ padding: "20px" }}>
        <h1>Emergency Contacts</h1>
        <p>Vehicle: {vehicle.plate_number} ({vehicle.make} {vehicle.model})</p>

        {vehicle.ice_contacts && vehicle.ice_contacts.length > 0 ? (
          <ul>
            {vehicle.ice_contacts.map((c, idx) => (
              <li key={idx}>
                {c.name} — {c.phone} ({c.relationship}){" "}
                <a
                  href={`tel:${c.phone}`}
                  style={{
                    marginLeft: "10px",
                    padding: "5px 10px",
                    backgroundColor: "#28a745",
                    color: "white",
                    borderRadius: "5px",
                    textDecoration: "none"
                  }}
                >
                  Call
                </a>
              </li>
            ))}
          </ul>
        ) : (
          <p>No emergency contacts found.</p>
        )}

        <h2>Send Owner a Message</h2>
        <button onClick={() => sendPresetEmail("Your car lights are on.")}
          style={{ marginRight: "10px", padding: "10px", cursor: "pointer" }}>Lights On</button>
        <button onClick={() => sendPresetEmail("Your car is blocking access.")}
          style={{ marginRight: "10px", padding: "10px", cursor: "pointer" }}>Blocking Access</button>
        <button onClick={() => sendPresetEmail("Your alarm is going off.")}
          style={{ padding: "10px", cursor: "pointer" }}>Alarm Triggered</button>
      </div>
    );
  }

  // If vehicle not exists → show form (includes owner email)
  return (
    <div style={{ padding: "20px" }}>
      <h1>Activate Your QR</h1>
      <form onSubmit={handleSubmit} style={{ maxWidth: "400px" }}>
        <input
          type="text"
          name="plate_number"
          placeholder="Plate Number"
          value={formData.plate_number}
          onChange={handleChange}
          required
          style={{ width: "100%", marginBottom: "10px" }}
        />
        <input
          type="text"
          name="make"
          placeholder="Make"
          value={formData.make}
          onChange={handleChange}
          required
          style={{ width: "100%", marginBottom: "10px" }}
        />
        <input
          type="text"
          name="model"
          placeholder="Model"
          value={formData.model}
          onChange={handleChange}
          required
          style={{ width: "100%", marginBottom: "10px" }}
        />
        <input
          type="email"
          name="owner_email"
          placeholder="Owner Email"
          value={formData.owner_email}
          onChange={handleChange}
          required
          style={{ width: "100%", marginBottom: "10px" }}
        />

        <h3>Emergency Contact</h3>
        <input
          type="text"
          name="ice_name"
          placeholder="Contact Name"
          value={formData.ice_name}
          onChange={handleChange}
          required
          style={{ width: "100%", marginBottom: "10px" }}
        />
        <input
          type="tel"
          name="ice_phone"
          placeholder="Contact Phone"
          value={formData.ice_phone}
          onChange={handleChange}
          required
          style={{ width: "100%", marginBottom: "10px" }}
        />
        <input
          type="text"
          name="ice_relationship"
          placeholder="Relationship"
          value={formData.ice_relationship}
          onChange={handleChange}
          required
          style={{ width: "100%", marginBottom: "10px" }}
        />

        <button
          type="submit"
          style={{
            padding: "10px 20px",
            backgroundColor: "#007bff",
            color: "white",
            border: "none",
            borderRadius: "5px"
          }}
        >
          Activate QR
        </button>
      </form>
    </div>
  );
}